
import streamlit as st
import json, os, datetime
from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer
from reportlab.lib.styles import getSampleStyleSheet

DATA="data.json"

if not os.path.exists(DATA):
    json.dump({"users":[],"quizzes":[],"history":[],"feedback":[]},open(DATA,"w"))

def load(): return json.load(open(DATA))
def save(d): json.dump(d,open(DATA,"w"))

data=load()

st.set_page_config(layout="wide")

st.markdown("""
<style>
.stApp {
background-image: url("data:image/png;base64,");
background-size: cover;
background-position: center;
background-attachment: fixed;
}
</style>
""", unsafe_allow_html=True)


st.title("Quiz System")

menu=st.sidebar.selectbox("Menu",["Login","Register"])

# -------- AUTH --------
if menu=="Register":
    n=st.text_input("Name"); e=st.text_input("Email")
    r=st.selectbox("Role",["Student","Faculty"])
    p=st.text_input("Password",type="password")
    c=st.text_input("Confirm",type="password")
    if st.button("Register"):
        if p!=c: st.error("Mismatch")
        else:
            data["users"].append({"name":n,"email":e,"role":r,"password":p})
            save(data); st.success("Registered")

if menu=="Login":
    e=st.text_input("Email"); p=st.text_input("Password",type="password")
    if st.button("Login"):
        u=next((x for x in data["users"] if x["email"]==e and x["password"]==p),None)
        if u: st.session_state["user"]=u
        else: st.error("Invalid")

# -------- DASHBOARD --------
if "user" in st.session_state:
    u=st.session_state["user"]
    if st.sidebar.button("Logout"):
        del st.session_state["user"]; st.rerun()

    st.sidebar.write(u["name"],u["role"])

    # STUDENT
    if u["role"]=="Student":
        t1,t2,t3=st.tabs(["Profile","Take Quiz","History"])

        with t1:
            st.write(u)
            fb=st.text_area("Feedback")
            if st.button("Send"):
                data["feedback"].append({"name":u["name"],"fb":fb})
                save(data); st.success("Sent")

        with t2:
            if not data["quizzes"]: st.warning("No quiz")
            else:
                qn=[q["title"] for q in data["quizzes"]]
                sel=st.selectbox("Quiz",qn)
                qz=next(q for q in data["quizzes"] if q["title"]==sel)

                end=datetime.datetime.strptime(qz["deadline"],"%Y-%m-%d")
                if datetime.datetime.now()>end:
                    st.error("Deadline over")
                else:
                    st.info(f"Time limit: {int(qz['time'])//60} min")
                    answers=[]
                    for i,q in enumerate(qz["questions"]):
                        answers.append(st.radio(q["question"],q["options"],key=i))

                    if st.button("Submit"):
                        sc=0; rep=[]
                        for i,q in enumerate(qz["questions"]):
                            if answers[i]==q["answer"]: sc+=1
                            rep.append((q["question"],answers[i],q["answer"]))
                        pct=round(sc/len(qz["questions"])*100,2)

                        data["history"].append({"user":u["name"],"quiz":sel,"score":sc,"pct":pct,"rep":rep})
                        save(data)

                        st.success(f"{sc} | {pct}%")

                        # PDF
                        pdf="report.pdf"
                        doc=SimpleDocTemplate(pdf)
                        styles=getSampleStyleSheet()
                        flow=[]
                        for q,a,c in rep:
                            flow.append(Paragraph(f"Q:{q}",styles["Normal"]))
                            flow.append(Paragraph(f"A:{a} | C:{c}",styles["Normal"]))
                            flow.append(Spacer(1,10))
                        doc.build(flow)

                        with open(pdf,"rb") as f:
                            st.download_button("Download Report",f,"report.pdf")

        with t3:
            for h in data["history"]:
                if h["user"]==u["name"]:
                    st.write(f"{h['quiz']} | {h['score']} | {h['pct']}%")

    # FACULTY
    if u["role"]=="Faculty":
        t1,t2,t3=st.tabs(["Create","Analytics","Feedback"])

        with t1:
            title=st.text_input("Title")
            time=st.number_input("Time(sec)",10,600)
            deadline=st.date_input("Deadline")

            n=st.number_input("Qn",1,10)
            qs=[]
            for i in range(int(n)):
                q=st.text_input(f"Q{i}",key=f"q{i}")
                o1=st.text_input(f"O1{i}",key=f"o1{i}")
                o2=st.text_input(f"O2{i}",key=f"o2{i}")
                o3=st.text_input(f"O3{i}",key=f"o3{i}")
                o4=st.text_input(f"O4{i}",key=f"o4{i}")
                a=st.selectbox("Ans",[o1,o2,o3,o4],key=f"a{i}")
                qs.append({"question":q,"options":[o1,o2,o3,o4],"answer":a})

            if st.button("Create"):
                data["quizzes"].append({
                    "title":title,
                    "questions":qs,
                    "time":time,
                    "deadline":str(deadline)
                })
                save(data); st.success("Created")

        with t2:
            st.subheader("Analytics")
            for h in data["history"]:
                st.write(h["user"],h["quiz"],h["score"],h["pct"])

        with t3:
            for f in data["feedback"]:
                st.write(f["name"],":",f["fb"])
